codeExamples.code:
let name = "Wayne";
let age = 20;
let msg = `${name} 今年 ${age} 歲`;
console.log(msg);

// + 號：有字串就拼接
console.log("10" + 10);    // "1010"（字串拼接）
console.log(10 + 10);      // 20（數學加法）

// 用跳脫字元放引號
let msg1 = "他說\"你好\"";
console.log(msg1);

// 外單內雙，不用跳脫
let msg2 = '他說"你好"';
console.log(msg2);

// \n 換行
let msg3 = "第一行\n第二行";
console.log(msg3);

// 模板字串裡面可以直接放引號
let msg4 = `他說"你好"，她說'嗨'`;
console.log(msg4);

